+export fn pktline_decode(
+    data_ptr: [*]const u8,
+    data_len: usize,
+    offset: usize,
+    out_payload_offset: *usize,
+) i32 {
+    return protocol.decodePktLine(data_ptr[0..data_len], offset, out_payload_offset) catch -1;
